CREATE TABLE area_entropy ( -- 区域熵值表
  row_id INTEGER PRIMARY KEY, -- 行号
  area_name TEXT NOT NULL UNIQUE, -- 区域名称
  entropy_value INTEGER NOT NULL DEFAULT 0 CHECK(entropy_value >= 0 AND entropy_value <= 100), -- 信息熵
  status_note TEXT -- 状态备注
);

